svg.script:
(function () {
  var svg = document.documentElement;
  svg._chartInit = function (svgEl, ctx) {
    var ns          = 'http://www.w3.org/2000/svg';
    var dataLayerEl = svgEl.querySelector('#data-layer');
    var dotsL       = svgEl.querySelector('#dots-layer');
    var hitLayer    = svgEl.querySelector('#hit-layer');
    var tipLayer    = svgEl.querySelector('#tip-layer');
    var defs        = svgEl.querySelector('defs');
    var clipRect    = svgEl.querySelector('#chartclip rect');

    var series = [
      { id:1, cls:'series-1', label:'Cyan',
        vals:[38,42,46,50,55,60,66,72], ys:[342.4,311.7,294.1,268.1,261.2,221.8,205.0,165.6] },
      { id:2, cls:'series-2', label:'Emerald',
        vals:[32,35,38,41,45,50,56,62], ys:[394.1,373.9,360.8,346.4,344.2,320.2,315.6,281.4] },
      { id:3, cls:'series-3', label:'Amber',
        vals:[18,20,21,23,25,27,31,35], ys:[439.4,423.2,416.9,410.5,415.3,399.6,403.8,381.6] },
      { id:4, cls:'series-4', label:'Rose',
        vals:[11,12,13,14,15,17,19,22], ys:[468.3,459.3,457.1,457.1,455.5,444.2,453.9,437.7] },
      { id:5, cls:'series-5', label:'Violet',
        vals:[10,11,12,13,14,16,17,19], ys:[487.8,483.0,486.2,480.2,483.0,477.5,480.2,473.3] },
    ];

    var quarters = ["Q1 '22","Q2 '22","Q3 '22","Q4 '22","Q1 '23","Q2 '23","Q3 '23","Q4 '23"];
    var xs   = [68,171,274,377,480,583,686,789];
    var colW = 56;
    var plotT = 100, plotB = 504;
    var waveDelays = series.map(function(_, i) {
      return ctx.getStaggerDelay(i, series.length, null, svgEl);
    });

    var totals = xs.map(function(_,qi){
      return series.reduce(function(s,sr){ return s + sr.vals[qi]; }, 0);
    });

    var el = ctx.el;

    // Highlight the nearest stacked area boundary for the hovered quarter.
    function setSeriesActive(qi, mouseY) {
      var bestSid = ctx.getNearestSeriesIdAtColumn(series, qi, mouseY);
      ctx.setSeriesHoverState({
        activeSid: bestSid,
        seriesIds: series.map(function(s) { return s.id; }),
        lineSelector: '.line-path.series-{id}',
        areaSelector: '.area-path[data-series="{id}"]'
      });
    }
    // Remove the stacked-area series highlight after the column hover ends.
    function clearSeriesActive() {
      ctx.setSeriesHoverState({
        activeSid: null,
        seriesIds: series.map(function(s) { return s.id; }),
        lineSelector: '.line-path.series-{id}',
        areaSelector: '.area-path[data-series="{id}"]'
      });
    }

    xs.forEach(function(x, qi) {
      series.forEach(function(s) {
        var dot = el('circle', {
          cx:x, cy:s.ys[qi], r:4,
          'class':'col-dot ' + s.cls,
          style:'stroke:none', 'data-col':qi
        });
        dotsL.appendChild(dot);
      });
    });

    ctx.initStackedColumnHover({
      xs: xs,
      quarters: quarters,
      series: series,
      totals: totals,
      tipLayer: tipLayer,
      hitLayer: hitLayer,
      plotL: 42,
      plotR: 840,
      plotT: plotT,
      plotB: plotB,
      anchorY: 304,
      hitTop: 100,
      hitHeight: 404,
      hitHalfWidth: colW,
      hitMinX: 68,
      hitMaxX: 832,
      hitIdPrefix: 'hit',
      onEnter: function(qi, sp, tipG, ch) {
        var colDots = dotsL.querySelectorAll('.col-dot[data-col="'+qi+'"]');
        dataLayerEl.classList.add('hovering');
        ctx.setElementsActive(dotsL.querySelectorAll('.col-dot'), function(d) {
          return Array.prototype.indexOf.call(colDots, d) !== -1;
        });
        setSeriesActive(qi, sp.y);
        ctx.setOpacity(tipG, 1);
        ctx.setOpacity(ch, 1);
      },
      onMove: function(qi, sp) {
        setSeriesActive(qi, sp.y);
      },
      onLeave: function(qi, tipG, ch) {
        var colDots = dotsL.querySelectorAll('.col-dot[data-col="'+qi+'"]');
        clearSeriesActive();
        dataLayerEl.classList.remove('hovering');
        ctx.setClassState(colDots, 'active', false);
        ctx.setOpacity(tipG, null);
        ctx.setOpacity(ch, null);
      }
    });

    series.forEach(function(s, i) {
      var area = svgEl.querySelector('#area-' + s.id);
      if (!area) return;
      ctx.initAreaClipReveal({
        defs: defs,
        area: area,
        clipId: 'area-reveal-' + s.id,
        clipRect: clipRect,
        delay: waveDelays[i],
        duration: 1200
      });
    });

   /* Bottom-to-top wave reveal to match the stacked layer order. */
    ctx.initRevealSequence(svgEl.querySelectorAll('.line-path'), {
      animationName: 'drawWave',
      duration: 1.2,
      easing: 'cubic-bezier(0.4,0,0.2,1)',
      delays: waveDelays,
      reverse: true
    });

    setTimeout(function() {
      dataLayerEl.classList.add('ready');
    }, ctx.getRevealReadyDelayMs({ delays: waveDelays, duration: 1.2, buffer: 0.1 }));
  };
  if (window.bootstrapChart) { window.bootstrapChart(svg); }
}());
